@GetMapping("/api/customers/{id}/profile")
public ResponseEntity<CustomerProfileDto> getProfile(@PathVariable Long id) {
    return customerService.findById(id)
        .map(c -> {
            List<Order> recent = orderService.getRecentByCustomer(id);
            double totalSpend = orderService.getTotalSpend(id);
            return ResponseEntity.ok(new CustomerProfileDto(c, recent, totalSpend));
        })
        .orElse(ResponseEntity.notFound().build());
}

