// ProductService
public List<Product> search(String name, Double min, Double max) {
    return productRepository.findAll().stream()
        .filter(p -> name == null || p.getName().contains(name))
        .filter(p -> min == null || p.getPrice() >= min)
        .filter(p -> max == null || p.getPrice() <= max)
        .collect(Collectors.toList());
}

@PostMapping("/api/accounts/transfer")
public ResponseEntity<?> transfer(@RequestBody TransferRequest request) {
    Account from = accountService.findById(request.fromId())
        .orElseThrow(() -> new AccountNotFoundException("Source account not found."));
    Account to = accountService.findById(request.toId())
        .orElseThrow(() -> new AccountNotFoundException("Destination account not found."));
    if (from.getBalance() < request.amount()) {
        throw new InsufficientFundsException("Insufficient funds.");
    }
    accountService.transfer(from, to, request.amount());
    return ResponseEntity.ok("Transfer complete.");
}

@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(MethodArgumentNotValidException.class)
    public ResponseEntity<Map<String, String>> handleValidation(
            MethodArgumentNotValidException ex) {
        Map<String, String> errors = new LinkedHashMap<>();
        ex.getBindingResult().getFieldErrors().forEach(err ->
            errors.put(err.getField(), err.getDefaultMessage()));
        return ResponseEntity.badRequest().body(errors);
    }
}

