@Query("""
    SELECT MONTH(o.orderDate) as month, SUM(i.quantity * i.unitPrice) as total
    FROM Order o
    JOIN o.items i
    WHERE YEAR(o.orderDate) = :year
    GROUP BY MONTH(o.orderDate)
    ORDER BY month
    """)
